const createRouter = () => new Router({
  // mode: 'history', // require service support
  scrollBehavior: () => ({ y: 0 }),
  routes: constantRoutes
})

const router = createRouter()

// Detail see: https://github.com/vuejs/vue-router/issues/1234#issuecomment-357941465
export function resetRouter() {
  const newRouter = createRouter()
  router.matcher = newRouter.matcher // reset router
}

// 全局路由守卫
router.beforeEach((to, from, next) => {
  // 设置页面标题
  document.title = to.meta.title ? `${to.meta.title} - 茶叶小程序管理后台` : '茶叶小程序管理后台'
  
  // 判断是否需要登录权限
  if (to.path !== '/login' && to.path !== '/404') {
    // 检查是否已登录（包括localStorage中的token）
    const token = localStorage.getItem('Admin-Token')
    const userInfo = localStorage.getItem('adminUserInfo')
    
    if (!store.getters['user/isLoggedIn'] && (!token || !userInfo)) {
      // 未登录，重定向到登录页
      next({
        path: '/login',
        query: { redirect: to.fullPath }
      })
    } else {
      // 如果store中没有状态但localStorage有，恢复状态
      if (!store.getters['user/isLoggedIn'] && token && userInfo) {
        try {
          const parsedUserInfo = JSON.parse(userInfo)
          store.commit('user/SET_TOKEN', token)
          store.commit('user/SET_USER_INFO', parsedUserInfo)
        } catch (e) {
          console.error('Failed to parse user info:', e)
        }
      }
      // 已登录，允许访问
      next()
    }
  } else {
    // 登录页面，如果已登录则重定向到首页
    if (to.path === '/login') {
      const token = localStorage.getItem('Admin-Token')
      const userInfo = localStorage.getItem('adminUserInfo')
      if (store.getters['user/isLoggedIn'] || (token && userInfo)) {
        next({ path: '/' })
      } else {
        next()
      }
    } else {
      // 不需要登录权限的页面
      next()
    }
  }
})

export default router 