<template>
  <div class="app-wrapper" :class="{ 'mobile': device === 'mobile', 'hide-sidebar': !sidebar.opened }">
    <div class="sidebar-container">
      <div class="logo-container">
        <img src="../../assets/images/logo.png" class="sidebar-logo" alt="logo">
        <h1 class="sidebar-title">茶叶小程序管理</h1>
      </div>
      
      <div class="sidebar-menu-wrap">
        <el-menu
          :default-active="activeMenu"
          :collapse="!sidebar.opened"
          :background-color="variables.menuBg"
          :text-color="variables.menuText"
          :active-text-color="variables.menuActiveText"
          :unique-opened="false"
          :collapse-transition="false"
          mode="vertical"
        >
          <sidebar-item
            v-for="route in routes"
            :key="route.path"
            :item="route"
            :base-path="route.path"
          />
        </el-menu>
      </div>
    </div>
    
    <div class="main-container">
      <div class="navbar">
        <hamburger 
          :is-active="sidebar.opened" 
          class="hamburger-container" 
          @toggleClick="toggleSideBar" 
        />
        
        <breadcrumb class="breadcrumb-container" />
        
        <div class="right-menu">
          <el-dropdown class="avatar-container" trigger="click">
            <div class="avatar-wrapper">
              <img src="../../assets/images/avatar.jpg" class="user-avatar" alt="avatar">
              <i class="el-icon-caret-bottom" />
            </div>
            <el-dropdown-menu slot="dropdown" class="user-dropdown">
              <router-link to="/profile">
                <el-dropdown-item>个人中心</el-dropdown-item>
              </router-link>
              <el-dropdown-item divided @click.native="logout">
                <span style="display:block;">退出登录</span>
              </el-dropdown-item>
            </el-dropdown-menu>
          </el-dropdown>
        </div>
      </div>
      
      <div class="app-main">
        <transition name="fade-transform" mode="out-in">
          <router-view />
        </transition>
      </div>
    </div>
  </div>
</template>

<script>
import { mapGetters, mapActions } from 'vuex'
import Hamburger from './components/Hamburger'
import Breadcrumb from './components/Breadcrumb'
import SidebarItem from './components/SidebarItem'

export default {
  name: 'Layout',
  components: {
    Hamburger,
    Breadcrumb,
    SidebarItem
  },
  computed: {
    ...mapGetters([
      'sidebar'
    ]),
    routes() {
      return this.$router.options.routes.filter(route => {
        return !route.hidden && 
               route.path !== '/login' && 
               route.path !== '/404' && 
               route.path !== '/profile' &&
               route.path !== '/'
      })
    },
    activeMenu() {
      const { meta, path } = this.$route
      if (meta.activeMenu) {
        return meta.activeMenu
      }
      return path
    },
    variables() {
      return {
        menuBg: '#1d1e2b',
        menuText: '#aeb9cc',
        menuActiveText: '#ffffff'
      }
    },
    device() {
      return this.$store.state.app.device
    }
  },
  methods: {
    ...mapActions('app', ['toggleSideBar']),
    ...mapActions('user', ['logout']),
    
    async handleLogout() {
      await this.logout()
      this.$router.push('/login')
    }
  }
}
</script>

